import os
class FileLock:
    def __init__(self, lock_path):
        self.lp = lock_path
    def __enter__(self):
        if os.path.exists(self.lp):
            raise RuntimeError('Locked')
        open(self.lp, 'w').close()
        return self
    def __exit__(self, *args):
        if os.path.exists(self.lp):
            os.remove(self.lp)
